// T617 FlowCanvasWriter — BOLA + FLOW_IMMUTABLE gate
const FLOW_INDEX = 'xiigen-flow-canvases';
const FLOW_IMMUTABLE_STATES = ['PUBLISHED'] as const;

async writeCanvas(event: Record<string, unknown>): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.getTenantId(); // ALS only
  const flowId = event['flowId'] as string;

  // ORDER 1: BOLA — verify tenant owns this canvas
  const flowResult = await this.db.searchDocuments(FLOW_INDEX, { flowId });
  if (!flowResult.data?.length) return DataProcessResult.failure('FLOW_NOT_FOUND', ...);
  const flow = flowResult.data[0];
  if (flow['tenantId'] !== tenantId) {
    await this.queue.enqueue('FlowCanvasUpdateFailed', { flowId, reason: 'BOLA_VIOLATION' });
    return DataProcessResult.failure('BOLA_VIOLATION', 'Tenant does not own this canvas');
  }

  // ORDER 2: FLOW_IMMUTABLE — prevent writes to published flows
  if (FLOW_IMMUTABLE_STATES.includes(flow['status'] as typeof FLOW_IMMUTABLE_STATES[number])) {
    await this.queue.enqueue('FlowImmutableRejected', { flowId, status: flow['status'] });
    return DataProcessResult.failure('FLOW_IMMUTABLE', 'Published flows cannot be modified');
  }

  // DNA-8: audit BEFORE enqueue
  await this.db.storeDocument(FLOW_AUDIT_INDEX, { flowId, action: 'CANVAS_UPDATED', tenantId });
  await this.queue.enqueue('FlowCanvasUpdated', { flowId, tenantId });
  return DataProcessResult.success({ flowId });
}

// T618 DFS cycle detection + type compatibility
const WHITE = 'WHITE', GRAY = 'GRAY', BLACK = 'BLACK';

function detectCycle(nodes: string[], edges: Edge[]): boolean {
  const color = new Map(nodes.map(n => [n, WHITE]));
  const adj = buildAdjacency(edges);
  function dfs(node: string): boolean {
    color.set(node, GRAY);
    for (const neighbor of adj.get(node) ?? []) {
      if (color.get(neighbor) === GRAY) return true; // cycle!
      if (color.get(neighbor) === WHITE && dfs(neighbor)) return true;
    }
    color.set(node, BLACK);
    return false;
  }
  return nodes.some(n => color.get(n) === WHITE && dfs(n));
}

