// T620 CodeInjectionProcessor — version lock + pre-write audit
const INJECTION_LOCK_PREFIX = 'injection-version-lock' as const;

async processInjection(event: Record<string, unknown>): Promise<DataProcessResult<Record<string, unknown>>> {
  const nodeId = event['nodeId'] as string;
  const version = event['version'] as string;

  // ORDER 1: version lock
  const lockKey = `${INJECTION_LOCK_PREFIX}:${nodeId}:${version}`;
  const lockResult = await this.db.searchDocuments(INJECTION_LOCKS_INDEX, { lockKey });
  if (lockResult.data?.length) {
    return DataProcessResult.failure('INJECTION_CONFLICT', 'Version already being injected');
  }
  await this.db.storeDocument(INJECTION_LOCKS_INDEX, { lockKey, nodeId, version, lockedAt: new Date().toISOString() });

  // ORDER 2: pre-write audit (rollback pointer) — APPEND-ONLY
  await this.db.storeDocument(INJECTION_AUDIT_INDEX, { nodeId, version, phase: 'PRE_WRITE', payload: event, auditedAt: new Date().toISOString() });

  // ORDER 3: inject
  // ... injection logic ...

  // ORDER 4: result audit (append-only) + DNA-8
  await this.db.storeDocument(INJECTION_AUDIT_INDEX, { nodeId, version, phase: 'COMPLETE', result: 'SUCCESS', completedAt: new Date().toISOString() });
  await this.queue.enqueue('CodeInjected', { nodeId, version, tenantId: this.getTenantId() });
  return DataProcessResult.success({ nodeId, version });
}

// T619 NodeTypeRegistrar — SETNX + atomic dual write + redis.del on failure
const NODE_TYPE_LOCK_PREFIX = 'node-type-reg-lock' as const;

async registerNodeType(event: Record<string, unknown>): Promise<DataProcessResult<Record<string, unknown>>> {
  const nodeTypeId = event['nodeTypeId'] as string;
  const lockKey = `${NODE_TYPE_LOCK_PREFIX}:${nodeTypeId}`;

  // ORDER 1: SETNX
  const lockResult = await this.db.searchDocuments(NODE_TYPE_LOCKS_INDEX, { lockKey });
  if (lockResult.data?.length) {
    return DataProcessResult.failure('NODE_TYPE_ALREADY_EXISTS', `Node type ${nodeTypeId} already registered`);
  }
  await this.db.storeDocument(NODE_TYPE_LOCKS_INDEX, { lockKey, nodeTypeId, lockedAt: new Date().toISOString() });

  try {
    // ORDER 2: first write — nodeType record
    await this.db.storeDocument(NODE_TYPES_INDEX, { nodeTypeId, ...event, knowledgeScope: 'GLOBAL' });
    // ORDER 3: second write — capability index entry
    await this.db.storeDocument(CAPABILITY_INDEX, { nodeTypeId, capabilities: event['capabilities'] });
  } catch (err) {
    // redis.del on failure — release lock to prevent hung state
    await this.db.deleteDocument(NODE_TYPE_LOCKS_INDEX, lockKey).catch(() => {});
    return DataProcessResult.failure('NODE_TYPE_WRITE_FAILED', (err as Error).message);
  }

  await this.db.storeDocument(NODE_TYPE_AUDIT_INDEX, { nodeTypeId, action: 'REGISTERED' });
  await this.queue.enqueue('NodeTypeRegistered', { nodeTypeId, tenantId: this.getTenantId() });
  return DataProcessResult.success({ nodeTypeId });
}
